package linker

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/plugin/buildpack"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/plugin/linker"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type LinkerProxy struct {
	linker.UnimplementedLinkerServer
	client linker.LinkerClient
}

func init() {
	proxyutil.Register(&linker.Linker_ServiceDesc, NewLinkerProxy)
}
func NewLinkerProxy(cc grpc.ClientConnInterface) linker.LinkerServer {
	return &LinkerProxy{client: linker.NewLinkerClient(cc)}
}
func (p *LinkerProxy) Link(ctx context.Context, in *buildpack.Bundle) (*linker.LinkerResponse, error) {
	return proxyutil.ProxyMethod[buildpack.Bundle, linker.LinkerResponse](p.client.Link)(ctx, in)
}
